 1	import { type FC, useState } from 'react';
 2	import { useWatch } from 'react-hook-form';
 3	
 4	import ExpandableReviewSection from '@components/ExpandableReviewSection/ExpandableReviewSection';
 5	import {
 6	  Button,
 7	  ButtonVariant,
 8	  DescriptionList,
 9	  DescriptionListDescription,
10	  DescriptionListGroup,
11	  DescriptionListTerm,
12	  Modal,
13	  ModalVariant,
14	  useWizardContext,
15	} from '@patternfly/react-core';
16	import { useForkliftTranslation } from '@utils/i18n';
17	
18	import { planStepNames, PlanWizardStepId } from '../../constants';
19	import { useCreatePlanFormContext } from '../../hooks/useCreatePlanFormContext';
20	import { VmFormFieldId } from '../virtual-machines/constants';
21	import VirtualMachinesTable from '../virtual-machines/VirtualMachinesTable';
22	
23	const VirtualMachinesReviewSection: FC = () => {
24	  const { t } = useForkliftTranslation();
25	  const { goToStepById } = useWizardContext();
26	  const { control } = useCreatePlanFormContext();
27	  const [isModalOpen, setIsModalOpen] = useState(false);
28	  const vms = useWatch({
29	    control,
30	    name: VmFormFieldId.Vms,
31	  });
32	  const vmCount = Object.values(vms).length;
33	
34	  return (
35	    <ExpandableReviewSection
36	      title={planStepNames[PlanWizardStepId.VirtualMachines]}
37	      testId="review-virtual-machines-section"
38	      onEditClick={() => {
39	        goToStepById(PlanWizardStepId.VirtualMachines);
40	      }}
41	    >
42	      <DescriptionList isHorizontal horizontalTermWidthModifier={{ default: '18ch' }}>
43	        <DescriptionListGroup>
44	          <DescriptionListTerm>{t('Selected VMs')}</DescriptionListTerm>
45	
46	          <DescriptionListDescription data-testid="review-vm-count">
47	            <Button
48	              isInline
49	              variant={ButtonVariant.link}
50	              onClick={() => {
51	                setIsModalOpen(true);
52	              }}
53	            >
54	              {t('{{count}} virtual machine selected', { count: vmCount })}
55	            </Button>
56	          </DescriptionListDescription>
57	        </DescriptionListGroup>
58	      </DescriptionList>
59	
60	      {isModalOpen && (
61	        <Modal
62	          isOpen
63	          variant={ModalVariant.large}
64	          title={t('Selected VMs')}
65	          onClose={() => {
66	            setIsModalOpen(false);
67	          }}
68	          actions={[
69	            <Button
70	              onClick={() => {
71	                setIsModalOpen(!isModalOpen);
72	              }}
73	            >
74	              {t('Close')}
75	            </Button>,
76	          ]}
77	        >
78	          <VirtualMachinesTable value={vms} showSelectedOnly />
79	        </Modal>
80	      )}
81	    </ExpandableReviewSection>
82	  );
83	};
84	
85	export default VirtualMachinesReviewSection;

